mapper.select:
SELECT uniqId , userTy , userId , userNm , emailAdres , groupId , sttus , sbscrbDe FROM ( SELECT ESNTL_ID AS uniqId , 'USR01' AS userTy , MBER_ID AS userId , MBER_NM AS userNm , MBER_EMAIL_ADRES AS emailAdres , GROUP_ID AS groupId , MBER_STTUS AS sttus , TO_CHAR(SBSCRB_DE,'YYYY-MM-DD') AS sbscrbDe FROM TB_GNRL_MBER UNION ALL SELECT ESNTL_ID AS uniqId , 'USR02' AS userTy , ENTRPRS_MBER_ID AS userId , CMPNY_NM AS userNm , APPLCNT_EMAIL_ADRES AS emailAdres , GROUP_ID AS groupId , ENTRPRS_MBER_STTUS AS sttus , TO_CHAR(SBSCRB_DE,'YYYY-MM-DD') AS sbscrbDe FROM TB_ENTRPRS_MBER UNION ALL SELECT ESNTL_ID AS uniqId , 'USR03' AS userTy , EMPLYR_ID AS userId , USER_NM AS userNm , EMAIL_ADRES AS emailAdres , GROUP_ID AS groupId , EMPLYR_STTUS_CODE AS sttus , TO_CHAR(SBSCRB_DE,'YYYY-MM-DD') AS sbscrbDe FROM TB_EMPLYR_INFO ) A WHERE 1 = 1
AND sttus LIKE #{sbscrbSttus}
AND userTy = #{userTy}
AND userId LIKE #{searchKeyword}
AND userNm LIKE '%' || #{searchKeyword} || '%'
ORDER BY sbscrbDe DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(1) AS totcnt FROM ( SELECT ESNTL_ID AS uniqId , 'USR01' AS userTy , MBER_ID AS userId , MBER_NM AS userNm , MBER_STTUS AS sttus FROM TB_GNRL_MBER UNION ALL SELECT ESNTL_ID AS uniqId , 'USR02' AS userTy , ENTRPRS_MBER_ID AS userId , CMPNY_NM AS userNm , ENTRPRS_MBER_STTUS AS sttus FROM TB_ENTRPRS_MBER UNION ALL SELECT ESNTL_ID AS uniqId , 'USR03' AS userTy , EMPLYR_ID AS userId , USER_NM AS userNm , EMPLYR_STTUS_CODE AS sttus FROM TB_EMPLYR_INFO ) A WHERE 1 = 1
AND sttus LIKE #{sbscrbSttus}
AND userTy = #{userTy}
AND userId LIKE #{searchKeyword}
AND userNm LIKE '%' || #{searchKeyword} || '%'

