INSERT  INTO TB_GNRL_MBER
      ( ESNTL_ID
      , MBER_ID
      , MBER_NM
      , PASSWORD
      , PASSWORD_HINT
      , PASSWORD_CNSR
      , IHIDNUM
      , SEXDSTN_CODE
      , ZIP
      , ADRES
      , AREA_NO
      , MBER_STTUS
      , DETAIL_ADRES
      , END_TELNO
      , MBTLNUM
      , GROUP_ID
      , MBER_FXNUM
      , MBER_EMAIL_ADRES
      , MIDDLE_TELNO
      , SBSCRB_DE )
VALUES  ( #{uniqId}
        , #{mberId}
        , #{mberNm}
        , #{password}
        , #{passwordHint}
        , #{passwordCnsr}
        , #{ihidnum}
        , #{sexdstnCode}
        , #{zip}
        , #{adres}
        , #{areaNo}
        , #{mberSttus}
        , #{detailAdres}
        , #{endTelno}
        , #{moblphonNo}
        , #{groupId}
        , #{mberFxnum}
        , #{mberEmailAdres}
        , #{middleTelno}
        , now() )

