UPDATE  TB_GNRL_MBER
   SET  MBER_STTUS = 'P'
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_ENTRPRS_MBER
   SET  ENTRPRS_MBER_STTUS = 'P'
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_EMPLYR_INFO
   SET  EMPLYR_STTUS_CODE = 'P'
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_ENTRPRS_MBER
   SET  ENTRPRS_MBER_STTUS = 'D'
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_EMPLYR_INFO
   SET  EMPLYR_STTUS_CODE = 'D'
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_GNRL_MBER
   SET  MBER_ID          = #{mberId}
      , MBER_NM          = #{mberNm}
      , PASSWORD_HINT    = #{passwordHint}
      , PASSWORD_CNSR    = #{passwordCnsr}
      , IHIDNUM          = #{ihidnum}
      , SEXDSTN_CODE     = #{sexdstnCode}
      , ZIP              = #{zip}
      , ADRES            = #{adres}
      , AREA_NO          = #{areaNo}
      , MBER_STTUS       = #{mberSttus}
      , DETAIL_ADRES     = #{detailAdres}
      , END_TELNO        = #{endTelno}
      , MBTLNUM          = #{moblphonNo}
      , GROUP_ID         = #{groupId}
      , MBER_FXNUM       = #{mberFxnum}
      , MBER_EMAIL_ADRES = #{mberEmailAdres}
      , MIDDLE_TELNO     = #{middleTelno}
 WHERE  ESNTL_ID = #{uniqId}

UPDATE  TB_GNRL_MBER
   SET  PASSWORD = #{password}
 WHERE  ESNTL_ID = #{uniqId}

